#include "pytorch_npu_helper.hpp"

at::Tensor conv_pointwise_2d_impl_npu(const at::Tensor& x, const at::Tensor& weight) {
    TORCH_CHECK(x.scalar_type() == at::kFloat, "ConvPointwise2dCustom supports float only");
    TORCH_CHECK(weight.scalar_type() == at::kFloat, "ConvPointwise2dCustom supports float only");
    at::Tensor y = at::empty({x.size(0), weight.size(0), x.size(2), x.size(3)}, x.options());
    EXEC_NPU_CMD(aclnnConvPointwise2dCustom, x, weight, y);
    return y;
}

TORCH_LIBRARY_IMPL(myops, PrivateUse1, m) {
    m.impl("conv_pointwise_2d_custom", &conv_pointwise_2d_impl_npu);
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
    m.def("conv_pointwise_2d_custom", &conv_pointwise_2d_impl_npu, "1x1 Pointwise Conv2d (ConvPointwise2dCustom on NPU)");
}
