template <typename T>
class KernelDataCopy {
public:
    __aicore__ inline KernelDataCopy() {}
    __aicore__ inline void Init(GM_ADDR x, GM_ADDR y, uint32_t xCountIn, uint32_t yCountIn, AscendC::TPipe* pipeIn)
    {
        this->pipe = pipeIn;
        this->xCount = xCountIn;
        this->yCount = yCountIn;

        this->xGm.SetGlobalBuffer(reinterpret_cast<__gm__ T*>(x));
        this->yGm.SetGlobalBuffer(reinterpret_cast<__gm__ T*>(y));
        this->pipe->InitBuffer(inQueueX, 1, xCount * sizeof(T));
        this->pipe->InitBuffer(outQueueY, 1, yCount * sizeof(T));
    }
    __aicore__ inline void Process()
    {
        CopyIn();
        Compute();
        CopyOut();
    }

private:
    __aicore__ inline void CopyIn()
    {
        AscendC::LocalTensor<T> xLocal = inQueueX.AllocTensor<T>();
        AscendC::Duplicate<T>(xLocal, 0, xCount);

        // 2D Padding场景，2维数据搬运
        // xGmShape：[2, 8]，搬运8列2行数据，左Padding 3，上Padding 1，右Padding 5，下Padding 1，xLocalShape：[4, 16]
        AscendC::NdDmaLoopInfo<2> loopInfo{{1, 8}, {1, 16}, {8, 2}, {3, 1}, {5, 1}};
        AscendC::NdDmaParams<T, 2> params{loopInfo, 0};  // padding的值为0
        AscendC::NdDmaDci();  // 刷新cache
        static constexpr AscendC::NdDmaConfig dmaConfig;  // // 使用默认参数，也可以不传
        AscendC::DataCopy<T, 2, dmaConfig>(xLocal, xGm, params);

        inQueueX.EnQue(xLocal);
    }
    __aicore__ inline void Compute()
    {
        AscendC::LocalTensor<T> xLocal = inQueueX.DeQue<T>();
        AscendC::LocalTensor<T> yLocal = outQueueY.AllocTensor<T>();
        AscendC::DataCopy(yLocal, xLocal, yCount);
        outQueueY.EnQue<T>(yLocal);
        inQueueX.FreeTensor(xLocal);
    }
    __aicore__ inline void CopyOut()
    {
        AscendC::LocalTensor<T> yLocal = outQueueY.DeQue<T>();
        AscendC::DataCopy(yGm, yLocal, yCount);
        outQueueY.FreeTensor(yLocal);
    }

private:
    AscendC::TPipe* pipe;
    AscendC::TQue<AscendC::TPosition::VECIN, 1> inQueueX;
    AscendC::TQue<AscendC::TPosition::VECOUT, 1> outQueueY;
    AscendC::GlobalTensor<T> xGm, yGm;
    uint32_t xCount, yCount;
}
